// Shelf Frontend Worker - serves static assets with SPA routing

const ASSETS = {
  '/index.html': { data: '', type: 'text/html; charset=utf-8' },
  '/manifest.json': { data: 'ewogICJuYW1lIjogIlNoZWxmIiwKICAic2hvcnRfbmFtZSI6ICJTaGVsZiIsCiAgInN0YXJ0X3VybCI6ICIvIiwKICAiZGlzcGxheSI6ICJzdGFuZGFsb25lIiwKICAiYmFja2dyb3VuZF9jb2xvciI6ICIjZmFmYWZhIiwKICAidGhlbWVfY29sb3IiOiAiIzI1NjNlYiIsCiAgImljb25zIjogW10KfQo=', type: 'application/json' },
  '/assets/index-k56c7zaX.css': { data: '', type: 'text/css; charset=utf-8' },
  '/assets/index-ZB3e_FQT.js': { data: '', type: 'application/javascript; charset=utf-8' },
};

// Decode base64 to Uint8Array
function b64ToBytes(b64) {
  const binStr = atob(b64);
  const bytes = new Uint8Array(binStr.length);
  for (let i = 0; i < binStr.length; i++) {
    bytes[i] = binStr.charCodeAt(i);
  }
  return bytes;
}

// Pre-decode all assets at startup
const DECODED = {};
for (const [path, asset] of Object.entries(ASSETS)) {
  DECODED[path] = { bytes: b64ToBytes(asset.data), type: asset.type };
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    let path = url.pathname;

    // Serve static asset if it exists
    if (DECODED[path]) {
      const asset = DECODED[path];
      return new Response(asset.bytes, {
        headers: {
          'Content-Type': asset.type,
          'Cache-Control': path.startsWith('/assets/') ? 'public, max-age=31536000, immutable' : 'public, max-age=3600',
          'Access-Control-Allow-Origin': '*',
        },
      });
    }

    // SPA fallback: serve index.html for all other paths
    const indexAsset = DECODED['/index.html'];
    return new Response(indexAsset.bytes, {
      headers: {
        'Content-Type': indexAsset.type,
        'Cache-Control': 'public, max-age=300',
        'Access-Control-Allow-Origin': '*',
      },
    });
  },
};
